solution:
function extractMiddle(arr) {
  const mid = Math.floor(arr.length / 2);
  if (arr.length % 2 === 0) {
    // For even length, take 2 elements centered around the middle
    return arr.splice(mid - 1, 2);
  } else {
    // For odd length, just take the exact middle element
    return arr.splice(mid, 1);
  }
}

