solution:
function removeEvensInPlace(arr) {
  // Loop backwards to safely mutate the array without index shifting bugs
  for (let i = arr.length - 1; i >= 0; i--) {
    if (arr[i] % 2 === 0) {
      arr.splice(i, 1);
    }
  }
  return arr;
}

