function moveElement(arr, fromIndex, toIndex) {
  // Remove the element and grab the first item from the returned array
  const extracted = arr.splice(fromIndex, 1)[0];
  // Insert it at the new position
  arr.splice(toIndex, 0, extracted);
  return arr;
}
